INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (252, 156198, 13, 573, '她的高傲与无奈', '11岁那年，无意中在一本书上翻到了张爱玲的照片，那时的书还没有多少彩页，泛黄的纸张，模糊的黑白印刷，一代奇女子却身着一袭华丽的旗袍，倨傲的仰着头……从那以后，我同绝大多数人一样，迷恋上这个女子的传奇、高贵以及骄傲。 
<br>初读张爱玲，在那个似懂非懂的年龄，是看不出什么的。只是那种朦朦胧胧的旧上海女人的小资情调，却一直留在了心头…… 
<br>再读张爱玲，在多愁善感的花季时节，是颇多感慨的。那句名言：呵，出名要趁早啊……对当时感觉郁郁不得志的我来说，多少是品得出点无奈的，在她的洞察世故的冷目之后，原也有此感慨的吗？ 
<br>三读张爱玲，是因为在杂志上看到了一篇关于她的文章《张爱玲的眼泪》，这才知道，即使高傲如她，也有低头顺眉、为爱情流泪的一天。关于她与胡兰成的那一段情，世人是颇多疑惑的。专门去看了胡兰成写的那本《今生今世》，合上书后，也不禁怀疑起张爱玲看男人的眼光。但毕竟她先是一个女人，然后才是文人啊！女人的心，都是水做的。女人最大的愿望，就是能找一个良人依靠。在看似坚强、高傲的张爱玲背后，也许还有很多是我们所不了解的，那种只属于女人的喜悦。但她所托却非良人啊！一个情路坎坷的女人，再多的高傲也只能化为无奈。 
<br>生命是一袭华丽的长袍，爬满了虱子。喜欢这句话，喜欢她说这句话时，那种对人生的讥讽。从她的小说、剧本里也隐隐约约地透露着这种对庸俗世人的嘲弄。那时的我，总是这样理解的，喜欢把这样一个高傲的女子放在高处往下看。其实把这句话放在她与胡兰成的爱情中，不也是一种无奈？在我们看来，她的才情、她的传奇、她的人生，就如同那一袭华丽的长袍，但不穿的人又怎会知道，这长袍竟爬满了虱子。 
<br>她终究是高傲的，她也终究是无奈的。在与胡兰成的那段情结束后，“我将是萎谢了。”她说。她用女人的柔情承受了一切，也放弃了在文学上宣泄的机会，从《金锁记》、《白玫瑰与红玫瑰》等所创造的艺术高峰，缓缓的下落…… 
<br>四读张爱玲，为了以上的文字。但读完后，感觉又回到了那个初读张爱玲的似懂非懂的年纪，心中感受最深的，还是那个穿旗袍、旧上海小资女人的高傲。这样也罢了吧，在那些喜爱张爱玲的人们心中，她是不需要如此多的无奈的。', '11岁那年，无意中在一本书上翻到了张爱玲的照片，那时的书还没有多少彩页，泛黄的纸张，模糊的黑白印刷，一代奇女子却身着一袭华丽的旗袍，倨傲的仰着头……从那以后，我同绝大多数人一样，迷恋上这个女子的传奇、高贵以及骄傲。

初读张爱玲，在那个似懂非懂的年龄，是看不出什么的。只是那种朦朦胧胧的旧上海女人的小资情调，却一直留在了心头……

再读张爱玲，在多愁善感的花季时节，是颇多感慨的。那句名言：呵，出名要趁早啊……对当时感觉郁郁不得志的我来说，多少是品得出点无奈的，在她的洞察世故的冷目之后，原也有此感慨的吗？

三读张爱玲，是因为在杂志上看到了一篇关于她的文章《张爱玲的眼泪》，这才知道，即使高傲如她，也有低头顺眉、为爱情流泪的一天。关于她与胡兰成的那一段情，世人是颇多疑惑的。专门去看了胡兰成写的那本《今生今世》，合上书后，也不禁怀疑起张爱玲看男人的眼光。但毕竟她先是一个女人，然后才是文人啊！女人的心，都是水做的。女人最大的愿望，就是能找一个良人依靠。在看似坚强、高傲的张爱玲背后，也许还有很多是我们所不了解的，那种只属于女人的喜悦。但她所托却非良人啊！一个情路坎坷的女人，再多的高傲也只能化为无奈。

生命是一袭华丽的长袍，爬满了虱子。喜欢这句话，喜欢她说这句话时，那种对人生的讥讽。从她的小说、剧本里也隐隐约约地透露着这种对庸俗世人的嘲弄。那时的我，总是这样理解的，喜欢把这样一个高傲的女子放在高处往下看。其实把这句话放在她与胡兰成的爱情中，不也是一种无奈？在我们看来，她的才情、她的传奇、她的人生，就如同那一袭华丽的长袍，但不穿的人又怎会知道，这长袍竟爬满了虱子。

她终究是高傲的，她也终究是无奈的。在与胡兰成的那段情结束后，“我将是萎谢了。”她说。她用女人的柔情承受了一切，也放弃了在文学上宣泄的机会，从《金锁记》、《白玫瑰与红玫瑰》等所创造的艺术高峰，缓缓的下落……

四读张爱玲，为了以上的文字。但读完后，感觉又回到了那个初读张爱玲的似懂非懂的年纪，心中感受最深的，还是那个穿旗袍、旧上海小资女人的高傲。这样也罢了吧，在那些喜爱张爱玲的人们心中，她是不需要如此多的无奈的。', '好的�矍槭悄阃高^一��人看到世界,�牡��矍槭悄��橐���人����世界...@@"', '2002-03-31 21:17:00', 14, '20020419174548_bbsid_156198_board_13_49d76d7da6.html', '20020419174548');
